# @cctt_verify {"v":2,"sym":"sympy.matrices.tests.test_interactions.test_classof","kind":"function","src_hash":"89599a197020e9de","in":{"base":"Any"},"out":{"base":"Any","pred":"classof(A, A) == Matrix and classof(B, B) == ImmutableMatrix and classof(A, B) == ImmutableMatrix and classof(B, A) == ImmutableMatrix"},"spec":{"lhs":"test_classof()","rhs":"test_classof produces the expected output","over":{"base":"Any"},"name":"test_classof_correct"},"guarantee":"test_classof produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.matrices.tests.test_interactions.test_classof_correct","statement":"Path(test_classof(x), test_classof produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"7f4cf2775f445f8d"}
def test_classof():
    A = Matrix(3, 3, range(9))
    B = ImmutableMatrix(3, 3, range(9))
    C = MatrixSymbol('C', 3, 3)
    assert classof(A, A) == Matrix
    assert classof(B, B) == ImmutableMatrix
    assert classof(A, B) == ImmutableMatrix
    assert classof(B, A) == ImmutableMatrix
    raises(TypeError, lambda: classof(A, C))
